@startuml
class Character {
    - GameDataRef _data;
    - sf::Sprite sprite;
    - sf::Vector2f position;
    - sf::Texture texture;
    - sf::Texture texture_flip;
    - sf::Texture run_right1;
    - sf::Texture run_right2;
    - sf::Texture run_left1;
    - sf::Texture run_left2;
    - bool flip = false;
    - sf::Clock animationClock;
    - int animationRun = 0;
    - bool air_texture = false;

    o sf::Vector2f velocity = {0,0};
    o float speed = 400.0f;
    o float jump_speed = 600.0f;
    o float slow_down = 0.0f, slow_down_ground = 40.0f, slow_down_air = 5.0f;
    o float speed_up = 0.0f, speed_up_ground = 40.0f, speed_up_air = 30.0f;
    o int max_jump = 1, jump = 0;
    o bool jump_done = false, on_ground = false;

    + void flipTexture();

    o Character(GameDataRef data);
    o void update();
    o void setTexture(6 Textures);
    o void setPosition(const sf::Vector2f& position_);
    o void setPosition(const float& x, const float& y);
    o sf::Vector2f getPosition();
    o void draw(sf::RenderWindow& renderWindow);
    o void move(sf::Vector2f movement);
    o void move(const float& x, const float& y);
    o sf::Vector2f nextPosition(sf::Vector2f movement);
    o sf::Sprite nextSprite(sf::Vector2f movement);
    o sf::Sprite& getSprite();
    o bool objectCollisionAndFalling(const sf::Sprite &object, const float& dt);
    o void updateVelocity(const float& dt);
    o void respawn(sf::Vector2f spawn);
    o void characterKeyboardInput();
}
@enduml
